import{_ as e,o as a,c as n,a2 as d}from"./chunks/framework.jUmBZPH5.js";const u=JSON.parse('{"title":"Supported Networks","description":"","frontmatter":{},"headers":[],"relativePath":"get-started/supported-networks.md","filePath":"get-started/supported-networks.md","lastUpdated":1775729021000}'),r={name:"get-started/supported-networks.md"};function o(i,t,s,l,c,h){return a(),n("div",null,[...t[0]||(t[0]=[d('<h1 id="supported-networks" tabindex="-1">Supported Networks <a class="header-anchor" href="#supported-networks" aria-label="Permalink to &quot;Supported Networks&quot;">​</a></h1><p>BitXPay supports 16 blockchain networks across both EVM and non-EVM ecosystems. All networks run on mainnet only. Choose the network that fits your assets, your users, and your fee requirements. This page provides an overview of the blockchain networks we currently support.</p><p><strong>Total Networks</strong>: 16<br><strong>EVM networks</strong>: 13<br><strong>Non-EVM Networks</strong>: 3</p><h2 id="what-is-a-network" tabindex="-1">What is a network? <a class="header-anchor" href="#what-is-a-network" aria-label="Permalink to &quot;What is a network?&quot;">​</a></h2><p>A network refers to the underlying blockchain infrastructure that powers transactions, decentralized applications (dApps), and smart contracts. Each network operates with its own set of rules, consensus mechanism, and native token. All wallets, addresses, and digital assets are created and exist specifically on one network.</p><h2 id="evm-networks" tabindex="-1">EVM networks <a class="header-anchor" href="#evm-networks" aria-label="Permalink to &quot;EVM networks&quot;">​</a></h2><p>Ethereum Virtual Machine-compatible chains share the same address format, tooling, and smart contract language (Solidity). An address on one EVM chain looks identical to an address on another, but they are entirely separate. <strong>Never send funds to an address on the wrong EVM chain.</strong></p><h2 id="non-evm-networks" tabindex="-1">Non-EVM networks <a class="header-anchor" href="#non-evm-networks" aria-label="Permalink to &quot;Non-EVM networks&quot;">​</a></h2><p>Bitcoin, Solana, and Tron use their own address formats and transaction models. Addresses are visually distinct and not compatible with EVM wallets. Each requires dedicated integration handling.</p><h2 id="network-list" tabindex="-1">Network List <a class="header-anchor" href="#network-list" aria-label="Permalink to &quot;Network List&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Network</th><th>Type</th><th>Status</th><th>Native token</th><th>Common assets</th></tr></thead><tbody><tr><td>01</td><td>Bitcoin</td><td>Non-EVM</td><td>Mainnet</td><td>BTC</td><td>BTC</td></tr><tr><td>02</td><td>Ethereum</td><td>EVM</td><td>Mainnet</td><td>ETH</td><td>ETH, USDT, USDC, DAI</td></tr><tr><td>03</td><td>BNB</td><td>EVM</td><td>Mainnet</td><td>BNB</td><td>BNB, USDT, BUSD, USDC</td></tr><tr><td>04</td><td>Solana</td><td>Non-EVM</td><td>Mainnet</td><td>SOL</td><td>SOL, USDC, USDT</td></tr><tr><td>05</td><td>Tron</td><td>Non-EVM</td><td>Mainnet</td><td>TRX</td><td>TRX, USDT (TRC-20)</td></tr><tr><td>06</td><td>Polygon</td><td>EVM</td><td>Mainnet</td><td>POL</td><td>POL, USDT, USDC, DAI</td></tr><tr><td>07</td><td>Avalanche</td><td>EVM</td><td>Mainnet</td><td>AVAX</td><td>AVAX, USDT, USDC</td></tr><tr><td>08</td><td>Arbitrum</td><td>EVM</td><td>Mainnet</td><td>ETH</td><td>ETH, USDT, USDC, ARB</td></tr><tr><td>09</td><td>Optimism</td><td>EVM</td><td>Mainnet</td><td>ETH</td><td>ETH, USDT, USDC, OP</td></tr><tr><td>10</td><td>Base</td><td>EVM</td><td>Mainnet</td><td>ETH</td><td>ETH, USDC, DAI</td></tr><tr><td>11</td><td>Linea</td><td>EVM</td><td>Mainnet</td><td>ETH</td><td>ETH, USDC</td></tr><tr><td>12</td><td>Gnosis</td><td>EVM</td><td>Mainnet</td><td>xDAI</td><td>xDAI, USDC, GNO</td></tr><tr><td>13</td><td>Sonic</td><td>EVM</td><td>Mainnet</td><td>S</td><td>S, USDC</td></tr><tr><td>14</td><td>Soneium</td><td>EVM</td><td>Mainnet</td><td>ETH</td><td>ETH, USDC</td></tr><tr><td>15</td><td>Unichain</td><td>EVM</td><td>Mainnet</td><td>ETH</td><td>ETH, USDC, UNI</td></tr><tr><td>16</td><td>Ink</td><td>EVM</td><td>Mainnet</td><td>ETH</td><td>ETH, USDC</td></tr></tbody></table><h2 id="mainnets" tabindex="-1">Mainnets <a class="header-anchor" href="#mainnets" aria-label="Permalink to &quot;Mainnets&quot;">​</a></h2><h3 id="production-only-environment" tabindex="-1">Production-only environment <a class="header-anchor" href="#production-only-environment" aria-label="Permalink to &quot;Production-only environment&quot;">​</a></h3><p>Use mainnets when building production-grade applications and handling real-world transactions through BitXPay APIs. This includes:</p><ul><li><strong>Sending actual cryptocurrency</strong> (such as withdrawals and payments)</li><li><strong>Interacting with live DeFi protocols</strong> (for example, staking, lending, or yield farming)</li><li><strong>Reading real-time on-chain data</strong> for dashboards, analytics, and reporting</li></ul><p>BitXPay APIs make production workflows significantly easier by allowing you to query account balances, transaction history, and blockchain events all without the need to run or maintain your own node.</p><h3 id="real-payments" tabindex="-1">Real payments <a class="header-anchor" href="#real-payments" aria-label="Permalink to &quot;Real payments&quot;">​</a></h3><p>Sending actual cryptocurrency — withdrawals, payouts, invoice settlements</p><h3 id="on-chain-data" tabindex="-1">On-chain data <a class="header-anchor" href="#on-chain-data" aria-label="Permalink to &quot;On-chain data&quot;">​</a></h3><p>Reading live balances, transaction history, and blockchain events</p><h3 id="defi-interactions" tabindex="-1">DeFi interactions <a class="header-anchor" href="#defi-interactions" aria-label="Permalink to &quot;DeFi interactions&quot;">​</a></h3><p>Staking, lending, yield farming, or any live protocol interaction</p><div class="warning custom-block"><p class="custom-block-title">Important Note</p><p>BitXPay currently operates exclusively on mainnets. We do not support testnets at this time.</p></div>',23)])])}const m=e(r,[["render",o]]);export{u as __pageData,m as default};
